var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……그래서, 변명은 그게 끝인가? 용병 혐오자 양반.","JPN":"……で、言い訳はそれで終わりか？　傭兵嫌いさん。","ENG":"... So, that’s your excuse, mercenary hater?","TWN":"……你還要再繼續辯解嗎？討厭傭兵的傢伙。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……대체 몇 번을 말해?! 그건 오해라니까!","JPN":"……いったい何回言えばわかるんだ！？　それは誤解だって！","ENG":"How many times do I have to tell you? It was all a misunderstanding!","TWN":"……到底要我說幾次？！那是誤會！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"오해?","JPN":"誤解？","ENG":"Misunderstanding?","TWN":"誤會？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"자네가 불쌍한 용병들을 다 때려죽이고 날 초공간으로 날려버리려고 했던 게 모두 오해일 뿐이라.","JPN":"あんたが可哀想な傭兵たちを全員殴り殺して、\\n俺を超空間にぶっ飛ばそうとしたのがすべて誤解だって？","ENG":"You tried to kill all those mercenaries, and then send me to hyperspace. And you claim that it was all just a misunderstanding?","TWN":"你把那些可憐的傭兵全都打死後，還想把我弄到超空間，這些全都是誤會？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"참 편리하군. 그렇지 않나?","JPN":"よく言うぜ、なあ？","ENG":"How convenient. Don’t you think?","TWN":"誤會這兩個字還真好用，你說是不？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"때려죽인 적 없어! 그리고 초공간으로 날아간 건 나였잖아!","JPN":"殴り殺してなんかない！　そもそも、超空間に飛ばされたのは俺の方だろ？","ENG":"I didn’t kill them! And I was the one who was sent into hyperspace!","TWN":"我沒有打死人！而且跑到超空間去的明明就是我！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"흐음……. 그랬던 것 같기도 하고, 아닌 것 같기도 하고…….","JPN":"ふむ……そうだったような、そうじゃなかったような……","ENG":"Hmm... Maybe you were. Or maybe you weren’t.","TWN":"嗯……你好像有說過，又好像沒有……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……다시 말하지만 그건 리플레이서의 협력자들을 색출하고 로스트 쉽을 확보하기 위한 작전이었어.","JPN":"……もう一度言うが、あれはリプレイサーの協力者をあぶり出して、\\nロストシップを確保するための作戦だったんだ。","ENG":"... I’m telling you, I did what I did to find the Replacer spies and secure the Lost Ship.","TWN":"……我再說一次，那是為了找出克隆集團的同夥和失落艦船的策略！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"항복 권유를 거부하고 교전 상황으로 만든 건 오히려 그쪽이었지!","JPN":"降伏勧告を断って交戦状態にしたのはむしろそっちだろうが！","ENG":"You were the one who refused to surrender and started fighting!","TWN":"況且，拒絕投降導致雙方開戰的罪魁禍首，明明就是閣下！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"얌전히 항복한 다른 녀석들은 제네바 협약에 따라 전시 포로로 대우해 줬다고.","JPN":"大人しく投降した他の奴らは、\\nジュネーブ条約に基づいて戦時捕虜として待遇してやったんだぞ。","ENG":"Those who surrendered were treated fairly in accordance with the Geneva Conventions.","TWN":"人家明明就說，只要乖乖投降，就根據日內瓦公約給予戰俘的待遇！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"미안하지만 어딘지도 모르는 이면세계에서 남에게 내 목숨을 맡기는 취미는 없거든.","JPN":"悪いが、未知の裏世界で他人に自分の命を預ける趣味はないんだ。","ENG":"Sorry, but I don’t like letting others decide my fate in the Counterside.","TWN":"很抱歉，我沒興趣在陌生的異界裡把性命交給其他人。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그리고 로스트 쉽에서도 미래에서 온 살인 기계처럼 날 제거하려고 하지 않았나?","JPN":"それにロストシップに乗ってからも、未来から来た殺人兵器みたいに俺を消そうとしただろ？","ENG":"Plus, you tried to kill me in the Lost Ship as well, like a killing machine sent from the future.","TWN":"而且在失落艦船裡，還有像是來自未來的殺人機器想殺我欸？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"물론 실패했지만 말이야.","JPN":"もちろん失敗したがな。","ENG":"You failed, though.","TWN":"雖然是沒有成功。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"죽인다고 한 적 없다니까! 다리만 부러뜨린다고 했었지!","JPN":"殺すなんて言ってなかっただろ！　足を折ってやるみたいなことは言ったけど！","ENG":"I didn’t try to kill you! I only wanted to break your legs!","TWN":"我沒有說要殺掉你！只說要打斷你的腿而已！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"애초에 내가 끝장을 보려고 했으면 그쪽이 아직 살아 있을 것 같아?","JPN":"そもそも俺が本気だったら、そっちこそこうやって生き延びられたと思うか？","ENG":"If I really wanted to kill you, you wouldn’t be here.","TWN":"要是我想殺你的話，閣下現在還能活著嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"하, 패배자의 변명이 아주 달콤하군.","JPN":"へっ、負け犬のくせに口だけは達者だな。","ENG":"Hah, says a loser.","TWN":"哈，失敗者總是喜歡找藉口。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"아무튼 기억해 두라고, 제이슨…… 뭐시기 대령님.","JPN":"とにかく覚えておけよ、ジェイソン……なんとか大佐殿。","ENG":"Anyway, never forget, Colonel Jason... whatever your name is.","TWN":"總之你記住，傑森……什麼上校。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그쪽에게 패배를 맛 보여 준 최고의 두뇌파 용병.","JPN":"あんたに敗北を味わわせた最高の頭脳派傭兵、","ENG":"This is the Intelligent Mercenary who defeated you.","TWN":"讓你嚐到失敗滋味的這個人，"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"존 더 스마트가이, 메이슨의 이름을.","JPN":"ジョン・ザ・スマートガイ・メイソンの名をな。","ENG":"John ”the Smart Guy” Mason.","TWN":"就是頭腦派傭兵，聰明的約翰·梅森！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"내 이름은 제이크 워커다! 벌써 세 번이나 말했어!","JPN":"俺の名はジェイク・ウォーカーだ！　もう三度目だぞ！","ENG":"My name is Jake Walker! I already told you thrice!","TWN":"我叫傑克·沃克！我已經跟你說了三次！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"알겠으니까 소리 좀 그만 질러, 제이미 왓슨 대령.","JPN":"わかったからギャーギャー言うな、ジェイミー・ワトソン大佐。","ENG":"Okay, stop yelling, Colonel Jamie Watson.","TWN":"聽到了，你小聲一點，傑米·沃森上校。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그래서 다시 한 번 요점만 묻지. 그쪽은 용병 혐오자가 아니라는 건가?","JPN":"それで、もう一度要点だけ聞こう。あんたは傭兵嫌いじゃないってことか？","ENG":"So let me ask you one more time. You’re not a mercenary hater?","TWN":"我再問你一次，你到底是不是討厭傭兵？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……아니, 용병 놈들은 믿을 수 없는 기생충 같은 것들이지.","JPN":"……いや、傭兵どもは信用ならない寄生虫みたいな奴らだ。","ENG":"Well, mercenaries are untrustworthy scum, usually...","TWN":"……是，傭兵都是些讓人信不過的寄生蟲！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"크흠, 물론 가끔 예외가 있긴 하지만…….","JPN":"こほん、もちろんたまに例外はあるがな……","ENG":"But, ahem, sometimes there are exceptions...","TWN":"咳咳，當然也不能一竿子打翻一船人啦……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……결론 났군.","JPN":"……はい、終了。","ENG":"Here you go.","TWN":"……有結論了。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그럼 만나서 반가웠고 점심 잘 먹었어. 다시 볼 일 없길 바라지.","JPN":"会えて嬉しかったよ。お昼もごちそうさま。もう二度と会わないことを祈るよ。","ENG":"It’s been a pleasure seeing you and thank you for the lunch. I hope we never meet again.","TWN":"很開心見到你，我吃飽了，後會無期。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"아, 물론 여기 계산은 그쪽이 하는 거겠지? 공무원이잖아?","JPN":"あ、もちろんここの料金はあんたが支払うよな？　公務員だもんな。","ENG":"Of course you’re buying lunch, right? You’re a civil servant!","TWN":"對了，這頓應該是你買單吧？你不是公務員嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"가긴 어딜 가! 아직 본론도 못 꺼냈다고!","JPN":"おい！　どこに行くんだ！　まだ本題に入ってないぞ！","ENG":"Don’t go anywhere yet! I haven’t told you why I’m here!","TWN":"你是要走去哪裡啦！我都還沒提到正事欸！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"……저기요, 대령님.","JPN":"……あの、大佐。","ENG":"Um, Colonel.","TWN":"……我說上校。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아가씨, 미안하지만 난 지금 당신 보스랑 깊은 이야기를 나누고 있어서 말이야. ","JPN":"お嬢さん、悪いけど俺は今君のボスと大事なお話中なんだ。","ENG":"Lady, I’m sorry, but I’m having a serious conversation with your boss.","TWN":"小姐，不好意思，我現在有話要跟你老闆說，"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"방해하지 말아 줬으면 좋겠어.","JPN":"どうか邪魔しないでくれるとありがたい。","ENG":"Please stop interrupting.","TWN":"請不要打擾我們。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그 대화가 시간낭비로 끝날 가능성이 커 보여서 말이죠.","JPN":"そのお話が時間の無駄になる可能性が高いかと。","ENG":"I think your conversation is going nowhere.","TWN":"你再說下去也只是浪費口水。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"서비스 업종에 오래 종사한 선배로서 충고 드리고 싶은 게 하나 있거든요.","JPN":"長らくサービス業に従事した先輩として、一点アドバイスしたいのですが。","ENG":"As a woman who has been in the service industry for a long time, I have some advice for you.","TWN":"身為服務業的前輩，我要給你個忠告。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……그게 뭐지?","JPN":"……何だ？","ENG":"What's that?","TWN":"……什麼忠告？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"예로부터 아쉬운 소리를 할 때는 먼저 <color=#ffd34c>성의</color>라는 걸 보여야 하는 법이죠.","JPN":"頼みたいことがあるなら、まずは<color=#ffd34c>誠意</color>を見せるべきだと、古くから決まっていますよ。","ENG":"When you’re asking for something, you have to show what you can <color=#ffd34c>give</color> first.","TWN":"自古以來，要談事情前都要先拿出<color=#ffd34c>誠意</color>吧？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"예를 들어 사무소의 파산을 막을 만큼 두둑한 크레딧 보따리 같은?","JPN":"たとえば、事務所の破産を防げるほどの大量のクレジットとか？","ENG":"Like... a lot of Credits, that can save our company from going bankrupt.","TWN":"像是可以阻止事務所破產的大筆金幣？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"파산?","JPN":"破産？","ENG":"Bankrupt?","TWN":"破產？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그게 무슨 소리야? 리플레이서 사태 해결에 공헌했다고 보상금이 꽤 나왔을 텐데?","JPN":"どういうことだ？　リプレイサー事件の解決に貢献した礼として\\n多額の報酬が支払われたはずだが？","ENG":"What are you talking about? You must have gotten a big reward for your contributions during the Replacer incident.","TWN":"那是什麼意思？不是因為解決克隆集團事件，而拿到很大筆獎金嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그…… 그 멍청이 3인방과 함께 부자가 됐다고 춤을 추는 걸 분명히 봤었다고.","JPN":"あの……あの3バカトリオと一緒に大金持ちになったと浮かれているところをこの目で見たぞ。","ENG":"I remember you dancing with that... stupid trio, screaming that you were now rich.","TWN":"我明明……還有看到他和蠢蛋三人幫一邊大喊我是有錢人，一邊跳舞啊？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그랬죠. 그 보상금을 제인 언니가 홀라당 들고 사라져 버리기 전까지는요.","JPN":"ええ、そうでした。\\nあの報酬をジェーンさんが一人で全部持ち逃げしてしまう前までは。","ENG":"Yes, until Jane ran away with all the money.","TWN":"你沒看錯，但那是在珍妮姊拿著獎金捲款潛逃前的事。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"장 웨이! 우리 사무소에서 그 저주 받을 이름은 금지야!","JPN":"ジャン・ウェイ！　我が事務所でその忌々しい名前を口に出すのは禁止だぞ！","ENG":"Zhang Wei! That cursed name is forbidden in my office!","TWN":"張維！不准你在提到那個該死的名字！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"빌어먹을…… 다시 만나면 그 때는 반드시 형과 천국에서 데이트하게 해 주겠어.","JPN":"ちくしょう……次に再会した時は、絶対兄貴と天国でデートさせてやる。","ENG":"Darn it... Next time I see her, I will send her to heaven so she can be with my brother again.","TWN":"該死的女人……要是再讓我見到她，我一定送她上天堂去和我哥約會！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……알 만하군.","JPN":"……なるほどな。","ENG":"I see how it went.","TWN":"……真是成事不足。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이번 일을 도와 주면 지난번 이상의 보상금이 지급될 거야.","JPN":"今回の件を手伝ってくれたら、前回以上の報酬が支給される予定だ。","ENG":"Well, if you help me this time, you’ll get a bigger reward than before.","TWN":"這次事成之後可以拿到比上次更多的獎金。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"세금 없이, 선금으로 30%…….","JPN":"非課税で、30％の前金を……","ENG":"No tax charged, and 30% upfront...","TWN":"不用繳稅，預付30%訂金……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"바로 그 이야기를 먼저 했었어야지!","JPN":"真っ先にその話をすべきだろ！","ENG":"Why didn’t you say so!","TWN":"這麼重要的事你怎麼不早說！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"메이슨 용병 사무소에 오신 걸 환영합니다, 대령님.","JPN":"メイソン傭兵事務所へようこそ、大佐。","ENG":"Welcome to the Mason Mercenary Office, Colonel.","TWN":"歡迎光臨梅森傭兵事務所，上校。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그래서 이번엔 또 무슨 용건이지? 댁들이랑은 이제 더 엮일 일 없을 줄 알았는데?","JPN":"それで今回はまたどんな用件だ？\\nあんたらとはこれ以上関わることはないと思ってたんだが。","ENG":"So, what’s this about? I thought I was never going to see you lot again.","TWN":"這次來訪是又有什麼事嗎？我原本以為我們應該不會再有什麼交集才對？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"안심해. 별거 아니니까.","JPN":"安心しろ。大したことじゃない。","ENG":"Relax, it’s not a difficult task.","TWN":"放心，不是什麼很困難的事。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"리플레이서 놈들이 숨겨 둔 물건 하나만 찾으면 돼. 정말 별거 아닌 일이지.","JPN":"リプレイサーどもが隠したものを一つだけ探してくれればいい。\\n本当に大したことじゃないんだ。","ENG":"All you have to do is to find something that Replacers have hidden. Really, it’s nothing serious.","TWN":"我要你幫我找出克隆集團藏起來的一樣東西，是不是很簡單？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"리플레이서? 또?","JPN":"リプレイサー？　またか？","ENG":"Replacers again?","TWN":"克隆集團？又來？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그런 건 당신네 부대에 있는 실력 좋은 녀석들한테 맡기면 되잖아?","JPN":"そんなの、あんたらの部隊にいる腕の良い奴らに頼めば済む話だろ？","ENG":"Don’t you have people in your team who can take care of that?","TWN":"你部隊裡應該也有些能幹的傢伙吧？幹嘛不找他們去找就好？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"굳이 날 부를 필요가 있나?","JPN":"わざわざ俺を呼ぶ必要があるか？","ENG":"Why would you need me?","TWN":"有必要特地來找我嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"뭔 소리예요! 일감 던져 주면 개처럼 받아 먹어야 할 상황인 거 몰라요?!","JPN":"何言ってるんですか！？\\n仕事を投げられたら犬のように食いつかなきゃならない状況なんですよ！？","ENG":"What is with you? I would think you'd jump in like a hungry dog at an offer like this!","TWN":"老闆你在胡說什麼！你把工作推掉，是要大家去喝西北風嗎？！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……그 여자가 평화롭던 내 사무소를 완전히 망쳐 놨어.","JPN":"……あの女、平和だった俺の事務所を完全にぶち壊したな。","ENG":"That witch ruined my peaceful office.","TWN":"……都是那個女人害的！把我一間好好的事務所搞成這樣！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"지금은 자세히 말해 줄 수 없어. 나름대로 사정이 있거든.","JPN":"今はまだ詳しい話はできない。それなりの事情があるんでね。","ENG":"I can’t tell you any more than that. It’s more like a need-to-know basis.","TWN":"我現在無法跟你解釋太多，總之我有我有的原因。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그리고 나는 꽤 바쁜 사람이야. 결정은 가급적 빨리 내려 주면 좋겠군.","JPN":"それに俺は結構多忙なんだぜ。できるだけ早く決めてほしい。","ENG":"And I’m a busy person. So I want your answer now.","TWN":"另外，我很忙，麻煩快點決定。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"咳咳……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};